<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>2048 Dark Edition</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --grid-bg: #2c3e50;
            --tile-empty: #34495e;
            --text-color: #ffffff;
            --font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        body {
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: var(--font-family);
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            margin: 0;
        }

        .header {
            text-align: center;
            margin-bottom: 20px;
        }

        #score {
            font-size: 2rem;
            font-weight: bold;
        }

        #board {
            display: grid;
            grid-template-columns: repeat(4, 80px);
            grid-template-rows: repeat(4, 80px);
            gap: 10px;
            background-color: var(--grid-bg);
            padding: 10px;
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
        }

        .tile {
            width: 80px;
            height: 80px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 1.8rem;
            font-weight: bold;
            border-radius: 4px;
            background-color: var(--tile-empty);
            transition: transform 0.1s ease, background-color 0.2s;
        }

        #reset {
            margin-top: 30px;
            padding: 10px 25px;
            font-size: 1rem;
            cursor: pointer;
            background-color: #e67e22;
            border: none;
            border-radius: 4px;
            color: white;
            font-weight: bold;
        }

        #reset:hover {
            background-color: #d35400;
        }

        /* Tile Colors */
        .tile-2 { background-color: #eee4da; color: #776e65; }
        .tile-4 { background-color: #ede0c8; color: #776e65; }
        .tile-8 { background-color: #f2b179; color: white; }
        .tile-16 { background-color: #f59563; color: white; }
        .tile-32 { background-color: #f67c5f; color: white; }
        .tile-64 { background-color: #ea6a5a; color: white; }
        .tile-128 { background-color: #edcf72; color: white; font-size: 1.5rem; }
        .tile-256 { background-color: #9b661e; color: white; font-size: 1.5rem; }
        .tile-512 { background-color: #7777ff; color: white; font-size: 1.5rem; }
        .tile-1024 { background-color: #bb33ff; color: white; font-size: 1.2rem; }
        .tile-2048 { background-color: #776aff; color: white; font-size: 1.2rem; }
    </style>
</head>
<body>

    <div class="header">
        <h1>2048</h1>
        <div>Score: <span id="score">0</span></div>
    </div>

    <div id="board"></div>

    <button id="reset">New Game</button>

    <script>
        let grid = [];
        let score = 0;
        const size = 4;

        function init() {
            grid = Array.from({ length: size }, () => Array(size).fill(0));
            score = 0;
            spawnTile();
            spawnTile();
            updateUI();
        }

        function spawnTile() {
            let emptyCells = [];
            for (let r = 0; r < size; r++) {
                for (let c = 0; c < size; c++) {
                    if (grid[r][c] === 0) emptyCells.push({r, c});
                }
            }
            if (emptyCells.length > 0) {
                const cell = emptyCells[Math.floor(Math.random() * emptyCells.length)];
                grid[cell.r][cell.c] = Math.random() < 0.9 ? 2 : 4;
            }
        }

        function updateUI() {
            const boardEl = document.getElementById('board');
            boardEl.innerHTML = '';
            for (let r = 0; r < size; r++) {
                for (let c = 0; c < size; c++) {
                    const val = grid[r][c];
                    const tile = document.createElement('div');
                    tile.className = `tile ${val > 0 ? 'tile-' + val : ''}`;
                    tile.textContent = val > 0 ? val : '';
                    boardEl.appendChild(tile);
                }
            }
            document.getElementById('score').textContent = score;
        }

        function processLine(line) {
            let filtered = line.filter(v => v !== 0);
            let result = [];
            for (let i = 0; i < filtered.length; i++) {
                if (i + 1 < filtered.length && filtered[i] === filtered[i+1]) {
                    result.push(filtered[i] * 2);
                    score += filtered[i] * 2;
                    i++;
                } else {
                    result.push(filtered[i]);
                }
            }
            while (result.length < size) result.push(0);
            return result;
        }

        function moveLeft() {
            let newGrid = grid.map(row => processLine([...row]));
            return newGrid;
        }

        function moveRight() {
            let newGrid = grid.map(row => {
                let reversed = [...row].reverse();
                let processed = processLine(reversed);
                return processed.reverse();
            });
            return newGrid;
        }

        function moveUp() {
            let newGrid = Array.from({ length: size }, () => Array(size).fill(0));
            for (let c = 0; c < size; c++) {
                let col = [];
                for (let r = 0; r < size; r++) col.push(grid[r][c]);
                let processed = processLine(col);
                for (let r = 0; r < size; r++) newGrid[r][c] = processed[r];
            }
            return newGrid;
        }

        function moveDown() {
            let newGrid = Array.from({ length: size }, () => Array(size).fill(0));
            for (let c = 0; c < size; c++) {
                let col = [];
                for (let r = size - 1; r >= 0; r--) col.push(grid[r][c]);
                let processed = processLine(col);
                for (let r = 0; r < size; r++) newGrid[size - 1 - r][c] = processed[r];
            }
            return newGrid;
        }

        const gameLogic = {
            size: 4,
            reset: () => {
                init();
                updateUI();
            },
            move: (dir) => {
                let oldGrid = grid.map(row => [...row]);
                let newGrid;
                if (dir === 'left') newGrid = moveLeft();
                else if (dir === 'right') newGrid = moveRight();
                else if (dir === 'up') newGrid = moveUp();
                else if (dir === 'down') newGrid = moveDown();

                let changed = false;
                for (let r = 0; r < size; r++) {
                    for (let c = 0; c < size; c++) {
                        if (newGrid[r][c] !== oldGrid[r][c]) {
                            changed = true;
                            break;
                        }
                    }
                }

                if (changed) {
                    grid = newGrid;
                    spawnTile();
                    updateUI();
                    return true;
                }
                return false;
            },
            board: () => grid,
            setBoard: (arr) => {
                grid = arr.map(row => [...row]);
                updateUI();
            },
            score: () => score
        };

        // Expose API
        window.game = gameLogic;

        // Event Listeners
        document.getElementById('reset').addEventListener('click', () => {
            gameLogic.reset();
        });

        window.addEventListener('keydown', (e) => {
            if (e.key === 'ArrowLeft') gameLogic.move('left');
            else if (e.key === 'ArrowRight') gameLogic.move('right');
            else if (e.key === 'ArrowUp') gameLogic.move('up');
            else if (e.key === 'ArrowDown') gameLogic.move('down');
        });

        // Initial Start
        init();
    </script>
</body>
</html>
